from typing import List

def common_in_nested_lists(nested_lsts: List[List[int]]) -> List[int]:
    all_vals = set()
    for each_lst in nested_lsts:
        all_vals.update(each_lst)
    return sorted(list(all_vals & set(nested_lsts[0])))

def bell_number(p):
    if (p == 0):
        return 1
    bell = [[0 for i in range(p + 1)] for i in range(p + 1)]
    bell[0][0] = 1
    for i in range(1, p + 1):
        bell[i][0] = bell[i - 1][i - 1]
        for j in range(1, i + 1):
            bell[i][j] = bell[i - 1][j - 1] + bell[i][j - 1]
    return bell[p][0]

