from scipy.special import factorial

def comb(n, m):
    return factorial(n) / (factorial(m) * factorial(n - m))

def eulerian_num(n, m):
    if m == n - 1:
        return comb(n, m) * (2 * m - 1)
    else:
        return sum(comb(m, k) * ((-1)**(m + k)) *
                   (factorial(m + 1) / ((m - k) * factorial(k))) *
                   eri_num(n - m - 1, k) for k in range(m + 1))
erf_num = eulerian_num  # Just alias the function name

