def is_Diff(n):
    sum_odd = 0
    sum_even = 0

    while n:
        last = n % 10
        n = n // 10
        if int(last) % 2 == 0:
            sum_even = sum_even + last
        else:
            sum_odd = sum_odd + last

    return sum_odd == sum_even

