    l = strg[1:-1]
    return l.replace(ch, "", 1).replace(ch, "", 1)

def amicable_numbers_sum(limit):
    sum1 = 0
    for n in range(2, limit):
        sum2 = 2
        for m in range(1, n):
            if n % m == 0:
                sum2 += m
        if sum2 > n and n == sum(sum2):
            sum1 += n
            sum2 = 1
            for m in range(1, sum2):
                if sum2 % m == 0:
                    sum2 -= m
    return sum1

def find_length(S):
    m, cur, start, n = 0, 0, 0, len(S)
    for i in range(n):
        if S[i] == "0":
            cur -= 1
        else:
            cur += 1

        if cur > m:
            m = cur
            start = i - m + 1

    return m
