import math

def dif_Square(num):
    s = int(math.sqrt(num))
    i = 1
    while (i <= s):
        if (s * s - i * i == num):
            return True
        i += 1
    return False

def multiply_int(x, y):
    p = 0
    for _ in range(abs(y)):
        p += abs(x)
    return p if x > 0 and y > 0 or x < 0 and y < 0 else -p

